   212	</head>
   213	<body>
   214	  <header class="sf-topbar">
   215	    <a class="sf-brand" href="/" title="Back to Seafile">
   216	      <img src="/media/img/seafile-logo.png" alt="Seafile" />
   217	    </a>
   218	    <span class="sf-section">NAS Sync</span>
   219	    <div class="sf-spacer"></div>
   220	    <a href="/" class="sf-back">&larr; Back to Seafile</a>
   221	    <a href="/accounts/logout/" class="sf-logout">Sign out</a>
   222	  </header>
   223	
   224	  <main>
   225	    <nav class="page-nav">
   226	      <a href="{{ url_for('status_page') }}"    class="nav-tab {% if active_tab == 'dashboard' %}active{% endif %}">Dashboard</a>
   227	      <a href="{{ url_for('controls_page') }}"  class="nav-tab {% if active_tab == 'controls' %}active{% endif %}">Controls</a>
   228	      <a href="{{ url_for('config_page') }}"    class="nav-tab {% if active_tab == 'config' %}active{% endif %}">Config</a>
   229	      <a href="{{ url_for('libraries_page') }}" class="nav-tab {% if active_tab == 'libraries' %}active{% endif %}">Libraries</a>
   230	      <a href="{{ url_for('index') }}"          class="nav-tab {% if active_tab == 'settings' %}active{% endif %}">Ingest Window</a>
   231	    </nav>
   232	
   233	    <h1 class="page-heading">Sync Status</h1>
   234	    <p class="page-sub">Live status from the seaf-cli containers. Updates every 10 seconds.</p>
   235	
   236	    <div id="cards">
   237	      {% for lib in libraries %}
   238	      <div class="card" id="card-{{ lib.id }}">
   239	        <div class="card-header">
   240	          <div class="card-header-left">
   241	            <h2>{{ lib.name }}</h2>
   242	            <span class="uuid">{{ lib.uuid }}</span>
   243	          </div>
   244	          <div style="display:flex;align-items:center;gap:12px;">
   245	            <div id="ctrl-{{ lib.id }}"></div>
   246	            <div class="last-seen" id="seen-{{ lib.id }}">Waiting for first report…</div>
   247	          </div>
   248	        </div>
   249	        <div id="body-{{ lib.id }}">
   250	          <div class="no-data">No data yet. Container may be starting up.</div>
   251	        </div>
   252	      </div>
   253	      {% endfor %}
   254	    </div>
   255	
   256	    <p class="refresh-note" id="refresh-note">Refreshing…</p>
   257	  </main>
   258	
   259	  <script>
   260	    const LIBRARIES = {{ libraries | tojson }};
   261	
   262	    function ago(seconds) {
   263	      if (seconds === null || seconds === undefined) return "unknown";
   264	      if (seconds < 5)  return "just now";
   265	      if (seconds < 60) return seconds + "s ago";
   266	      if (seconds < 3600) return Math.floor(seconds / 60) + "m ago";
   267	      return Math.floor(seconds / 3600) + "h ago";
   268	    }
   269	
   270	    function fmtFiles(n) {
   271	      if (n === null || n === undefined) return "—";
   272	      return n.toLocaleString();
   273	    }
   274	
   275	    function fmtIngestDays(d) {
   276	      if (d === null || d === undefined) return "—";
   277	      if (d === 0) return "All files";
   278	      return d + " days";
   279	    }
   280	
   281	    function badgeClass(entry, state, stale) {
   282	      if (stale) return "idle";
   283	      if (entry.paused) return "paused";
   284	      if (state === "synchronized") return "ok";
   285	      if (state === "uploading" || state === "downloading") return "busy";
   286	      if (state === "error") return "error";
   287	      return "idle";
   288	    }
   289	
   290	    function badgeLabel(entry, state, stale) {
   291	      if (stale) return "Offline";
   292	      if (!entry.daemon_alive) return "Daemon stopped";
   293	      if (entry.paused) return "Paused";
   294	      if (state === "synchronized") return "Synchronized";
   295	      if (state === "uploading") {
   296	        const pct = entry.repos[0]?.progress_pct;
   297	        const rate = entry.repos[0]?.rate_kb;
   298	        let label = "Uploading";
   299	        if (pct !== null && pct !== undefined) label += " " + pct + "%";
   300	        if (rate !== null && rate !== undefined && rate > 0) label += " · " + rate + " KB/s";
   301	        return label;
   302	      }
   303	      if (state === "downloading") return "Downloading";
   304	      if (state === "error") return "Error: " + (entry.repos[0]?.error || "unknown");
   305	      if (state === "waiting") return "Waiting to sync";
   306	      if (!state) return "Starting up…";
   307	      return state;
   308	    }
   309	
   310	    async function sendCommand(libraryUuid, verb, btn) {
   311	      btn.disabled = true;
   312	      try {
   313	        const resp = await fetch("{{ url_for('api_command') }}", {
   314	          method: "POST",
   315	          headers: {"Content-Type": "application/json"},
   316	          body: JSON.stringify({library_uuid: libraryUuid, verb}),
   317	        });
   318	        if (!resp.ok) throw new Error("server error");
   319	      } catch (e) {
   320	        alert("Failed to send command. Try again.");
   321	      } finally {
   322	        btn.disabled = false;
   323	      }
   324	    }
   325	
   326	    function renderCard(lib, data) {
   327	      const bodyEl   = document.getElementById("body-" + lib.id);
   328	      const seenEl   = document.getElementById("seen-" + lib.id);
   329	
   330	      if (!data) {
   331	        seenEl.textContent = "No report received";
   332	        seenEl.className = "last-seen stale";
   333	        bodyEl.innerHTML = '<div class="no-data">Container has not reported in yet.</div>';
   334	        return;
   335	      }
   336	
   337	      const stale   = data.stale;
   338	      const secsAgo = data.seconds_ago;
   339	      seenEl.textContent = "Last seen: " + ago(secsAgo);
   340	      seenEl.className   = "last-seen" + (stale ? " stale" : "");
   341	
   342	      const ctrlEl = document.getElementById("ctrl-" + lib.id);
   343	      if (!stale && data.daemon_alive) {
   344	        if (data.paused) {
   345	          ctrlEl.innerHTML = `<button class="btn-resume" onclick="sendCommand('${lib.uuid}','resume',this)">Resume</button>`;
   346	        } else {
   347	          ctrlEl.innerHTML = `<button class="btn-pause" onclick="sendCommand('${lib.uuid}','pause',this)">Pause</button>`;
   348	        }
   349	      } else {
   350	        ctrlEl.innerHTML = "";
   351	      }
   352	
   353	      const repo  = (data.repos && data.repos[0]) || null;
   354	      const state = repo ? repo.state : null;
   355	      const cls   = badgeClass(data, state, stale);
   356	      const label = badgeLabel(data, state, stale);
   357	
   358	      let progressBar = "";
   359	      if (!stale && state === "uploading" && repo && repo.progress_pct !== null) {
   360	        progressBar = `<div class="progress-bar-wrap">
   361	          <div class="progress-bar" style="width:${repo.progress_pct}%"></div>
   362	        </div>`;
   363	      }
   364	
   365	      const lastIngest = data.last_ingest_at
   366	        ? new Date(data.last_ingest_at).toLocaleString()
   367	        : "—";
   368	
   369	      bodyEl.innerHTML = `
   370	        <div class="status-badge ${cls}">
   371	          <span class="dot ${cls}"></span>
   372	          ${label}
   373	        </div>
   374	        ${progressBar}
   375	        <div class="meta-grid">
   376	          <div class="meta-item">
   377	            <label>Daemon</label>
   378	            <div class="val">${data.daemon_alive ? "Running (PID " + data.daemon_pid + ")" : "Not running"}</div>
   379	          </div>
   380	          <div class="meta-item">
   381	            <label>Staging files</label>
   382	            <div class="val">${fmtFiles(data.staging_files)}</div>
   383	          </div>
   384	          <div class="meta-item">
   385	            <label>Ingest window</label>
   386	            <div class="val">${fmtIngestDays(data.ingest_days)}</div>
   387	          </div>
   388	          <div class="meta-item">
   389	            <label>Last ingest</label>
   390	            <div class="val">${lastIngest}</div>
   391	          </div>
   392	        </div>
   393	      `;
   394	    }
   395	
   396	    async function refresh() {
   397	      try {
   398	        const resp = await fetch("{{ url_for('api_status_data') }}");
   399	        if (!resp.ok) return;
   400	        const data = await resp.json();
   401	        LIBRARIES.forEach(lib => {
   402	          // match by container_id (matches lib.id) or by library_uuid
   403	          const entry = data[lib.id]
   404	            || Object.values(data).find(e => e.library_uuid === lib.uuid)
   405	            || null;
   406	          renderCard(lib, entry);
   407	        });
   408	        document.getElementById("refresh-note").textContent =
   409	          "Last refreshed: " + new Date().toLocaleTimeString();
   410	      } catch (e) {
   411	        document.getElementById("refresh-note").textContent = "Refresh failed — retrying…";
   412	      }
   413	    }
   414	
   415	    refresh();
   416	    setInterval(refresh, 10000);
   417	  </script>
   418	</body>
   419	</html>

