def is_seafile_admin() -> bool:
    """Return True if the request has a valid Seafile admin session.

    Uses the seahub_auth cookie (format: email@token) for Token auth over HTTPS.
    The session-cookie approach (sessionid + http://seafile) triggers a 308
    HTTP→HTTPS redirect that drops the Cookie header, causing spurious 403s.
    """
    seahub_auth = request.cookies.get("seahub_auth", "")
    if not seahub_auth or "@" not in seahub_auth:
        return False
    # seahub_auth = "user@example.com@<40-char-hex-token>" — split on last @
    token = seahub_auth.rsplit("@", 1)[-1]
    if not token:
        return False
    try:
        req = urllib.request.Request(
            f"https://{_SEAFILE_PUBLIC_HOST}/api/v2.1/admin/sysinfo/",
            headers={"Authorization": f"Token {token}"},
        )
        with urllib.request.urlopen(req, timeout=5) as resp:
            return resp.status == 200
    except urllib.error.HTTPError as exc:
        # 403 = authenticated but not admin; 401 = not authenticated — both mean no access
        if exc.code in (401, 403):
            return False
        raise
    except Exception:
        return False


def _login_redirect():
    """Redirect an unauthenticated browser to the Seafile login, then back here.

    Caddy strips the /nas-settings prefix before the request reaches Flask, so
    request.path is the stripped path (e.g. "/"). Prepend script_root
    ("/nas-settings") so `next` returns the user to the panel, not Seafile's root.
    """
    full_path = request.script_root + request.path
    next_url = urllib.parse.quote(full_path, safe="")
    return redirect(f"{_SEAFILE_LOGIN_URL}?next={next_url}")


